 1→import { createContext, useContext } from 'react';
 2→
 3→interface GridContextValue {
 4→  activeIndex: number;
 5→  setActiveIndex: (index: number) => void;
 6→  columns: number;
 7→}
 8→
 9→export const GridContext = createContext<GridContextValue | null>(null);
10→
11→export function useGridContext(): GridContextValue {
12→  const context = useContext(GridContext);
13→  if (!context) {
14→    throw new Error('useGridContext must be used within a Grid');
15→  }
16→  return context;
17→}
