  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './grid.scss';
 10→import { GridContext } from './grid_context';
 11→
 12→interface GridProps {
 13→  children: ReactNode;
 14→  itemCount: number;
 15→  columns?: number;
 16→  onActiveIndexChange?: (index: number) => void;
 17→  onAction?: (index: number) => void;
 18→}
 19→
 20→export function Grid({
 21→  children,
 22→  itemCount,
 23→  columns = 4,
 24→  onActiveIndexChange,
 25→  onAction,
 26→}: GridProps) {
 27→  const [activeIndex, setActiveIndexRaw] = useState(0);
 28→  const containerRef = useRef<HTMLDivElement>(null);
 29→
 30→  const setActiveIndex = useCallback(
 31→    (index: number) => {
 32→      setActiveIndexRaw(index);
 33→      onActiveIndexChange?.(index);
 34→    },
 35→    [onActiveIndexChange],
 36→  );
 37→
 38→  useEffect(() => {
 39→    if (itemCount === 0) {
 40→      setActiveIndex(0);
 41→    } else if (activeIndex >= itemCount) {
 42→      setActiveIndex(itemCount - 1);
 43→    }
 44→  }, [
 45→    itemCount,
 46→    activeIndex,
 47→    setActiveIndex,
 48→  ]);
 49→
 50→  useEffect(() => {
 51→    const container = containerRef.current;
 52→    if (!container) return;
 53→
 54→    const activeElement = container.querySelector<HTMLElement>(
 55→      `[data-grid-index="${activeIndex}"]`,
 56→    );
 57→    activeElement?.scrollIntoView({ block: 'nearest' });
 58→  }, [activeIndex]);
 59→
 60→  useEffect(() => {
 61→    function handleKeyDown(e: KeyboardEvent) {
 62→      if (itemCount === 0) return;
 63→      if (e.metaKey || e.ctrlKey || e.altKey) return;
 64→
 65→      const row = Math.floor(activeIndex / columns);
 66→      const col = activeIndex % columns;
 67→      const totalRows = Math.ceil(itemCount / columns);
 68→
 69→      switch (e.key) {
 70→        case 'ArrowRight': {
 71→          e.preventDefault();
 72→          const next = activeIndex + 1;
 73→          setActiveIndex(next < itemCount ? next : 0);
 74→          break;
 75→        }
 76→        case 'ArrowLeft': {
 77→          e.preventDefault();
 78→          const prev = activeIndex - 1;
 79→          setActiveIndex(prev >= 0 ? prev : itemCount - 1);
 80→          break;
 81→        }
 82→        case 'ArrowDown': {
 83→          e.preventDefault();
 84→          const nextRow = row + 1;
 85→          if (nextRow < totalRows) {
 86→            const nextIndex = nextRow * columns + col;
 87→            setActiveIndex(nextIndex < itemCount ? nextIndex : itemCount - 1);
 88→          } else {
 89→            setActiveIndex(col < itemCount ? col : 0);
 90→          }
 91→          break;
 92→        }
 93→        case 'ArrowUp': {
 94→          e.preventDefault();
 95→          const prevRow = row - 1;
 96→          if (prevRow >= 0) {
 97→            setActiveIndex(prevRow * columns + col);
 98→          } else {
 99→            const lastRowIndex = (totalRows - 1) * columns + col;
100→            setActiveIndex(
101→              lastRowIndex < itemCount ? lastRowIndex : itemCount - 1,
102→            );
103→          }
104→          break;
105→        }
106→        case 'Enter': {
107→          e.preventDefault();
108→          onAction?.(activeIndex);
109→          break;
110→        }
111→      }
112→    }
113→
114→    window.addEventListener('keydown', handleKeyDown);
115→    return () => window.removeEventListener('keydown', handleKeyDown);
116→  }, [
117→    activeIndex,
118→    itemCount,
119→    columns,
120→    setActiveIndex,
121→    onAction,
122→  ]);
123→
124→  const contextValue = useMemo(
125→    () => ({
126→      activeIndex,
127→      setActiveIndex,
128→      columns,
129→    }),
130→    [
131→      activeIndex,
132→      setActiveIndex,
133→      columns,
134→    ],
135→  );
136→
137→  return (
138→    <GridContext value={contextValue}>
139→      <div
140→        ref={containerRef}
141→        className="grid"
142→        role="listbox"
143→        id="command-grid"
144→        style={{ '--grid-columns': columns } as React.CSSProperties}
145→      >
146→        {children}
147→      </div>
148→    </GridContext>
149→  );
150→}
