 4→
 5→export interface GridItemProps {
 6→  index: number;
 7→  icon?: ReactNode;
 8→  title: string;
 9→  subtitle?: string;
10→  onClick?: () => void;
11→}
12→
13→export function GridItem({
14→  index,
15→  icon,
16→  title,
17→  subtitle,
18→  onClick,
19→}: GridItemProps) {
20→  const { activeIndex, setActiveIndex } = useGridContext();
21→  const isActive = activeIndex === index;
22→
23→  const handleMouseEnter = useCallback(() => {
24→    setActiveIndex(index);
25→  }, [
26→    index,
27→    setActiveIndex,
28→  ]);
29→
30→  return (
31→    <div
32→      id={`grid-item-${index}`}
33→      className={`grid-item${isActive ? ' grid-item--active' : ''}`}
34→      data-grid-index={index}
35→      role="option"
36→      aria-selected={isActive}
37→      onMouseEnter={handleMouseEnter}
38→      onClick={onClick}
39→    >
40→      {icon && <span className="grid-item__icon">{icon}</span>}
41→      <span className="grid-item__title">{title}</span>
42→      {subtitle && <span className="grid-item__subtitle">{subtitle}</span>}
43→    </div>
44→  );
45→}
