  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { ActionPanel } from './components/action_panel/action_panel';
  3→import { CommandPalette } from './components/command_palette/command_palette';
  4→import { Detail } from './components/detail/detail';
  5→import { DetailMetadata } from './components/detail/detail_metadata';
  6→import { EmptyState } from './components/empty_state/empty_state';
  7→import { Grid, GridItem } from './components/grid';
  8→import { Kbd } from './components/kbd/kbd';
  9→import { List, ListItem, ListSection } from './components/list';
 10→import type { BreadcrumbItem } from './components/search_bar/search_bar';
 11→import { SearchBar } from './components/search_bar/search_bar';
 12→import { ToastContainer } from './components/toast/toast_container';
 13→import { MOCK_COLORS, MOCK_SECTIONS } from './data/mock_data';
 14→import { useToast } from './hooks/use_toast';
 15→import type {
 16→  GridItemData,
 17→  ListItemData,
 18→  ListItemMetadataEntry,
 19→  SectionData,
 20→} from './types';
 21→
 22→function filterSections(sections: SectionData[], query: string): SectionData[] {
 23→  if (!query) return sections;
 24→  const lower = query.toLowerCase();
 25→  return sections
 26→    .map(section => ({
 27→      ...section,
 28→      items: section.items.filter(
 29→        item =>
 30→          item.title.toLowerCase().includes(lower) ||
 31→          item.subtitle?.toLowerCase().includes(lower),
 32→      ),
 33→    }))
 34→    .filter(section => section.items.length > 0);
 35→}
 36→
 37→function filterColors(colors: GridItemData[], query: string): GridItemData[] {
 38→  if (!query) return colors;
 39→  const lower = query.toLowerCase();
 40→  return colors.filter(
 41→    c =>
 42→      c.title.toLowerCase().includes(lower) ||
 43→      c.subtitle?.toLowerCase().includes(lower),
 44→  );
 45→}
 46→
 47→function flattenItems(sections: SectionData[]): ListItemData[] {
 48→  return sections.flatMap(s => s.items);
 49→}
 50→
 51→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 52→  switch (entry.type) {
 53→    case 'label':
 54→      return (
 55→        <DetailMetadata.Label
 56→          key={index}
 57→          title={entry.title}
 58→          text={entry.text}
 59→        />
 60→      );
 61→    case 'link':
 62→      return (
 63→        <DetailMetadata.Link
 64→          key={index}
 65→          title={entry.title}
 66→          text={entry.text}
 67→          target={entry.target}
 68→        />
 69→      );
 70→    case 'tag-list':
 71→      return (
 72→        <DetailMetadata.TagList key={index} title={entry.title}>
 73→          {entry.tags.map(tag => (
 74→            <DetailMetadata.Tag
 75→              key={tag.text}
 76→              text={tag.text}
 77→              color={tag.color}
 78→            />
 79→          ))}
 80→        </DetailMetadata.TagList>
 81→      );
 82→    case 'separator':
 83→      return <DetailMetadata.Separator key={index} />;
 84→  }
 85→}
 86→
 87→function ColorSwatch({ color }: { color: string }) {
 88→  return (
 89→    <div
 90→      style={{
 91→        width: 64,
 92→        height: 64,
 93→        borderRadius: 12,
 94→        backgroundColor: color,
 95→      }}
 96→    />
 97→  );
 98→}
 99→
100→function SearchIcon() {
101→  return (
102→    <svg
103→      width="48"
104→      height="48"
105→      viewBox="0 0 48 48"
106→      fill="none"
107→      xmlns="http://www.w3.org/2000/svg"
108→    >
109→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
110→      <line
111→        x1="30"
112→        y1="30"
113→        x2="42"
114→        y2="42"
115→        stroke="currentColor"
116→        strokeWidth="3"
117→        strokeLinecap="round"
118→      />
119→    </svg>
120→  );
121→}
