123→type ViewMode = 'list' | 'grid';
124→
125→export function App() {
126→  const [query, setQuery] = useState('');
127→  const [selectedIndex, setSelectedIndex] = useState(0);
128→  const [actionsOpen, setActionsOpen] = useState(false);
129→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
130→  const [viewMode, setViewMode] = useState<ViewMode>('list');
131→  const { toasts, show: showToast, hide: hideToast } = useToast();
132→
133→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
134→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
135→  const filteredColors = useMemo(
136→    () => filterColors(MOCK_COLORS, query),
137→    [query],
138→  );
139→  const selectedItem =
140→    viewMode === 'list' ? (drilledItem ?? allItems[selectedIndex]) : undefined;
141→
142→  const handleQueryChange = useCallback((value: string) => {
143→    setQuery(value);
144→    setSelectedIndex(0);
145→    setActionsOpen(false);
146→  }, []);
147→
148→  const handleActiveIndexChange = useCallback((index: number) => {
149→    setSelectedIndex(index);
150→    setActionsOpen(false);
151→  }, []);
152→
153→  const handleDrillIn = useCallback(() => {
154→    const item = allItems[selectedIndex];
155→    if (item) {
156→      if (item.id === 'color-picker') {
157→        setViewMode('grid');
158→        setQuery('');
159→        setSelectedIndex(0);
160→        setActionsOpen(false);
161→        showToast({
162→          style: 'success',
163→          title: 'Opened Color Picker',
164→        });
165→      } else {
166→        setDrilledItem(item);
167→        setQuery('');
168→        setActionsOpen(false);
169→        showToast({
170→          style: 'success',
171→          title: `Opened ${item.title}`,
172→        });
173→      }
174→    }
175→  }, [
176→    allItems,
177→    selectedIndex,
178→    showToast,
179→  ]);
180→
181→  const handleDrillBack = useCallback(() => {
182→    setDrilledItem(null);
183→    setViewMode('list');
184→    setQuery('');
185→    setSelectedIndex(0);
186→    setActionsOpen(false);
187→  }, []);
188→
189→  const handleGridAction = useCallback(
190→    (index: number) => {
191→      const color = filteredColors[index];
192→      if (color) {
193→        showToast({
194→          style: 'info',
195→          title: 'Copied color',
196→          message: color.color,
197→        });
198→      }
199→    },
200→    [
201→      filteredColors,
202→      showToast,
203→    ],
204→  );
205→
206→  const breadcrumbs: BreadcrumbItem[] | undefined =
207→    viewMode === 'grid'
208→      ? [
209→          {
210→            label: 'Raycast',
211→            onBack: handleDrillBack,
212→          },
213→          { label: 'Color Picker' },
214→        ]
215→      : drilledItem
216→        ? [
217→            {
218→              label: 'Raycast',
219→              onBack: handleDrillBack,
220→            },
221→            { label: drilledItem.title },
222→          ]
223→        : undefined;
224→
225→  const toggleActions = useCallback(() => {
226→    setActionsOpen(prev => !prev);
227→  }, []);
228→
229→  const closeActions = useCallback(() => {
230→    setActionsOpen(false);
231→  }, []);
232→
233→  useEffect(() => {
234→    function handleKeyDown(e: KeyboardEvent) {
235→      if (e.key === 'k' && e.metaKey) {
236→        e.preventDefault();
237→        setActionsOpen(prev => !prev);
238→      }
239→    }
240→
241→    window.addEventListener('keydown', handleKeyDown);
242→    return () => window.removeEventListener('keydown', handleKeyDown);
243→  }, []);
244→
245→  const detail = selectedItem?.detail;
246→
247→  const dropdownActions = useMemo(
248→    () => [
249→      {
250→        label: 'Open',
251→        shortcut: <Kbd keys={['↵']} />,
252→        onClick: () => {
253→          if (selectedItem) {
254→            showToast({
255→              style: 'success',
256→              title: `Opened ${selectedItem.title}`,
257→            });
258→          }
259→        },
260→      },
261→      {
262→        label: 'Copy Name',
263→        shortcut: (
264→          <Kbd
265→            keys={[
266→              '⌘',
267→              'C',
268→            ]}
269→          />
270→        ),
271→        onClick: () => {
272→          if (selectedItem) {
273→            showToast({
274→              style: 'info',
275→              title: 'Copied to clipboard',
276→              message: selectedItem.title,
277→            });
278→          }
279→        },
280→      },
281→      {
282→        label: 'Show Detail',
283→        shortcut: (
284→          <Kbd
285→            keys={[
286→              '⌘',
287→              'D',
288→            ]}
289→          />
290→        ),
291→        onClick: () => {
292→          showToast({
293→            style: 'info',
294→            title: 'Detail panel toggled',
295→          });
296→        },
297→      },
298→      {
299→        label: 'Delete',
300→        shortcut: (
301→          <Kbd
302→            keys={[
303→              '⌘',
304→              '⌫',
305→            ]}
306→          />
307→        ),
308→        onClick: () => {
309→          showToast({
310→            style: 'error',
311→            title: 'Cannot delete',
312→            message: 'This item is read-only',
313→          });
314→        },
315→      },
316→    ],
317→    [
318→      selectedItem,
319→      showToast,
320→    ],
321→  );
322→
323→  const activeDescendantId =
324→    viewMode === 'grid'
325→      ? filteredColors.length > 0
326→        ? `grid-item-${selectedIndex}`
327→        : undefined
328→      : allItems.length > 0
329→        ? `list-item-${selectedIndex}`
330→        : undefined;
331→
332→  return (
333→    <CommandPalette isLoading>
334→      <SearchBar
335→        value={query}
336→        onChange={handleQueryChange}
337→        activeDescendantId={activeDescendantId}
338→        breadcrumbs={breadcrumbs}
339→      />
340→      <div
341→        className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
342→      >
343→        <div className="command-palette__list-container">
344→          {viewMode === 'grid' ? (
345→            filteredColors.length === 0 ? (
346→              <EmptyState
347→                icon={<SearchIcon />}
348→                title="No Colors"
349→                description="Try a different search term"
350→              />
351→            ) : (
352→              <Grid
353→                itemCount={filteredColors.length}
354→                columns={4}
355→                onActiveIndexChange={handleActiveIndexChange}
356→                onAction={handleGridAction}
357→              >
358→                {filteredColors.map((color, index) => (
359→                  <GridItem
360→                    key={color.id}
361→                    index={index}
362→                    icon={<ColorSwatch color={color.color} />}
363→                    title={color.title}
364→                    subtitle={color.subtitle}
365→                  />
366→                ))}
367→              </Grid>
368→            )
369→          ) : allItems.length === 0 ? (
370→            <EmptyState
371→              icon={<SearchIcon />}
372→              title="No Results"
373→              description="Try a different search term"
374→            />
375→          ) : (
376→            <List
377→              itemCount={allItems.length}
378→              onActiveIndexChange={handleActiveIndexChange}
379→              onAction={handleDrillIn}
380→            >
381→              {(() => {
382→                let globalIndex = 0;
383→                return filtered.map(section => (
384→                  <ListSection key={section.title} title={section.title}>
385→                    {section.items.map(item => {
386→                      const idx = globalIndex++;
387→                      return (
388→                        <ListItem
389→                          key={item.id}
390→                          index={idx}
391→                          title={item.title}
392→                          subtitle={item.subtitle}
393→                          icon={item.icon}
394→                          accessories={item.accessories}
395→                        />
396→                      );
397→                    })}
398→                  </ListSection>
399→                ));
400→              })()}
401→            </List>
402→          )}
403→        </div>
404→        {detail && (
405→          <Detail
406→            markdown={detail.markdown}
407→            metadata={
408→              detail.metadata ? (
409→                <DetailMetadata>
410→                  {detail.metadata.map(renderMetadataEntry)}
411→                </DetailMetadata>
412→              ) : undefined
413→            }
414→          />
415→        )}
416→      </div>
417→      <ActionPanel
418→        actions={[
419→          {
420→            label: 'Open',
421→            shortcut: <Kbd keys={['↵']} />,
422→          },
423→          {
424→            label: 'Actions',
425→            shortcut: (
426→              <Kbd
427→                keys={[
428→                  '⌘',
429→                  'K',
430→                ]}
431→              />
432→            ),
433→            onClick: toggleActions,
434→          },
435→        ]}
436→        dropdownOpen={actionsOpen}
437→        dropdownActions={dropdownActions}
438→        onDropdownClose={closeActions}
439→      />
440→      <ToastContainer toasts={toasts} onDismiss={hideToast} />
441→    </CommandPalette>
442→  );
443→}
